// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var aRecipients = [];
	var gr_allTasks = new GlideRecord('x_153465_discovert_route_task_instance');
	gr_allTasks.addQuery('u_task_tree', current.u_task_tree);
	gr_allTasks.query();
	while(gr_allTasks.next()){
		var assigned_to= gr_allTasks.getValue('assigned_to') + '';
		if( assigned_to != ''){
			aRecipients.push(assigned_to);
		}
		var task_owner = gr_allTasks.getValue('u_task_requester') + '';
		if( task_owner != ''){
			aRecipients.push(task_owner);
		}
		var reviewer = gr_allTasks.getValue('u_reviewer') + '';
		if( reviewer != ''){
			aRecipients.push(reviewer);
		}

		var on_behalf_of = gr_allTasks.getValue('on_behalf_of') + '';
		if( on_behalf_of != ''){
			aRecipients.push(on_behalf_of);
		}

	}
	if(aRecipients.length > 0){
		var au = new global.ArrayUtil();
		aRecipients = au.unique(aRecipients);		
		var recipients = aRecipients.join(',');
		gs.eventQueue("x_153465_discovert.TaskObjectiveChanged",current, recipients, previous.u_objective);
	}

})(current, previous);
